search.query:
* |   select ts_predicate_arma(day, total, 5, 1, 1, 1, 'avg') from  (
 select * from ( select *, max(day) over() as lastday  from (select to_unixtime( date_trunc('day',__time__))  as day ,  sum(PretaxAmount) as total     from instance_bill where productcode like '%%' group by day  order by day limit 1000)  ) where day < lastday 
)

